var s=context.state,a=context.action,m=context.memory;
var PI2=Math.PI*2,PI=Math.PI;
if(!m.t){m.t=0;m.lf=-99;}m.t++;
var angDiff=function(x,y){var d=(x-y)%PI2;if(d>PI)d-=PI2;if(d<-PI)d+=PI2;return d;};
var angTo=function(x1,y1,x2,y2){return Math.atan2(y2-y1,x2-x1);};
var myX=s.position.x,myY=s.position.y,myA=s.angle;
var dC=Math.sqrt((myX-450)*(myX-450)+(myY-450)*(myY-450));
var toC=s.angleToCenter;
var rem=context.round.remaining;
var closest=s.proximity[0]||{};
var front=s.scanner.robot[0]||false;

if(Math.random()<0.5)a.desiredForce=s.maxForce;

if(rem<5){
  if(dC>8){a.desiredAngle=toC;a.desiredForce=s.maxForce;}
  else a.desiredForce=0;
}else if(rem<12){
  a.desiredAngle=toC;a.desiredForce=s.maxForce;
  if(front&&front.active&&front.team!=s.team)a.desiredLaunch=true;
}else if(closest.entityType=='wall'){
  a.desiredAngle=toC;
}else if(front&&front.active&&front.team!=s.team){
  var range=front.range;
  var projSpeed=42;
  var tF=range/projSpeed;
  var pX=front.x+front.speed*Math.cos(front.angle)*tF;
  var pY=front.y+front.speed*Math.sin(front.angle)*tF;
  var lA=angTo(myX,myY,pX,pY);
  a.desiredAngle=lA;
  var aimErr=Math.abs(angDiff(myA,lA));
  var tgtW=Math.atan2(28,range);
  if(aimErr<tgtW&&(m.t-m.lf)>=30){
    a.desiredLaunch=true;m.lf=m.t;
  }
}else if(front&&(!front.active||front.team==s.team)){
  var dir2=(front.angleFromRobot-myA)<0?-1:1;
  a.desiredAngle=myA-(dir2*0.174533);
  a.desiredForce=s.maxForce/2;
}else if(dC>300){
  a.desiredAngle=toC;
  a.desiredForce=s.maxForce;
}else if(Math.random()<0.005){
  var maxvar=PI/4;
  a.desiredAngle=myA+(Math.random()*maxvar)-maxvar/2;
  a.desiredForce=0;
}
